类型 示例 清洗方法 HTML 实体 <code>&amp;nbsp;</code>, <code>&amp;lt;</code>, <code>&amp;gt;</code> HTML 实体解码 特殊空白 <code>\u200b</code> (零宽空格), <code>\xa0</code> (不换行空格) Unicode 规范化 控制字符 <code>\x00</code>, <code>\x08</code> 正则过滤 多余空白 连续空格、Tab、换行 规范化为空格 <pre><code>// 去除噪音字符
func CleanNoiseText(text string) string {
    // 1. 解码 HTML 实体
    text = html.UnescapeString(text)

    // 2. 规范化 Unicode
    text = strings.ToLower(text)

    // 3. 替换特殊空白字符为空格
    text = regexp.MustCompile(`[\x00-\x08\x0b\x0c\x0e-\x1f\x7f]`).ReplaceAllString(text, "")

    // 4. 规范化空白字符
    text = regexp.MustCompile(`[\t\p{Zs}]+`).ReplaceAllString(text, " ")

    // 5. 去除零宽字符
    text = regexp.MustCompile(`[\u200b-\u200f\u2028-\u202f\ufeff]`).ReplaceAllString(text, "")

    return strings.TrimSpace(text)
}
</code></pre>

策略 说明 适用场景 标签过滤 只保留 p, h1-h6, article 等标签 简单页面 CSS 选择器 根据 class/id 选择正文区域 复杂页面 基于 ML 使用模型识别正文区域 通用性要求高 <pre><code>// HTML 解析实现
func (p *HTMLParser) Parse(ctx context.Context, reader io.Reader) ([]core.TextBlock, error) {
    // 1. 解析 HTML
    root, err := html.Parse(reader)
    if err != nil {
        return nil, err
    }

    // 2. 使用 CSS 选择器提取正文
    selector := "article, .content, .post-content, main"
    contentNodes := p.querySelectorAll(root, selector)

    // 3. 提取文本并保持结构
    var blocks []core.TextBlock
    for _, node := range contentNodes {
        text := p.extractText(node)
        level := p.getHeadingLevel(node)
        blocks = append(blocks, core.TextBlock{
            Content:     text,
            HeadingLevel: level,
        })
    }

    return blocks, nil
}
